module mux2to1_64bit (
    input sel,
    input [63:0] in0,
    input [63:0] in1,
    output [63:0] out
);

    reg [63:0] obf_mux_out;  // Multiplexer output register

    always @(*) begin
        case (sel)
            1'b0: obf_mux_out = in0;
            1'b1: obf_mux_out = in1;
            default: obf_mux_out = 64'b0;  // Default case (should not occur)
        endcase
    end

    assign out = obf_mux_out;

endmodule
